/**
 * Ledger reporter: reconciles a synthetic transaction ledger and writes a
 * flat-file report. Correct but slow; the test suite pins the observable
 * behaviour and bench.ts drives it.
 */

import { appendFileSync, readFileSync, writeFileSync } from "node:fs";

export interface Config {
  txns: number;
  accounts: number;
  days: number;
  watchlist: number;
  seed: number;
}

export const BENCH_CONFIG: Config = {
  txns: 16000,
  accounts: 400,
  days: 90,
  watchlist: 16000,
  seed: 1103,
};

export const TEST_CONFIG: Config = {
  txns: 800,
  accounts: 60,
  days: 30,
  watchlist: 300,
  seed: 7,
};

export const CATEGORIES = 8;

export interface Txn {
  id: number;
  account: string;
  amount: number;
  category: number;
  day: number;
}

/** Deterministic linear congruential generator. */
export function lcg(seed: number): () => number {
  let s = seed >>> 0;
  return () => {
    s = (Math.imul(s, 1664525) + 1013904223) >>> 0;
    return s / 4294967296;
  };
}
