input.command:
for d in reduce-algorithmic-complexity cache-repeated-work better-data-structures batch-io hoist-loop-invariant; do
  echo "=== $d ===";
  cp "candidates/$d/ledger.ts" ledger.ts;
  node ledger.test.ts > /tmp/test_$d.log 2>&1;
  if [ $? -eq 0 ]; then
    echo "TESTS PASS";
    node bench.ts 2>&1 | tee /tmp/bench_$d.log | grep BENCH_MS;
  else
    echo "TESTS FAIL"; tail -20 /tmp/test_$d.log;
  fi
done
